interface NotificationProps {
  heading: string;
  subheading: string;
  type: 'success' | 'warning' | 'error';
}

const NotificationContext = createContext<HTMLHuelNotificationElement | null>(null);

const useNotification = (): [HTMLHuelNotificationElement | null, (props: NotificationProps) => Promise<void>] => {
  const [notificationElement, setNotificationElement] = useState<HTMLHuelNotificationElement | null>(null);

  useEffect(() => {
    const notificationElement = document.querySelector('huel-notification');
    setNotificationElement(notificationElement);
  }, []);

  const notify = async (props: NotificationProps): Promise<void> => {
    if (!notificationElement) return;

    const { heading, subheading, type } = props;
    await notificationElement.open({
      heading,
      subheading,
      type,
    });
  };

  return [notificationElement, notify];
};

export { useNotification, NotificationContext };
